                </div>

                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-slate-900 dark:text-white">{activity.description}</p>
                  <p className="text-xs text-slate-500 dark:text-slate-400 mt-1 flex items-center gap-1">
                    <ClockIcon className="w-3 h-3" />
                    {new Date(activity.timestamp).toLocaleString()}
                  </p>
                </div>

                <span
                  className={`flex-shrink-0 px-3 py-1 rounded-full text-xs font-bold border ${getActivityColor(
                    activity.type,
                  )}`}
                >
                  {activity.type}
                </span>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="p-12 text-center">
          <div className="w-16 h-16 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center mx-auto mb-4">
            <ActivityIcon className="w-8 h-8 text-slate-300 dark:text-slate-600" />
          </div>
          <p className="text-slate-500 dark:text-slate-400 font-medium">No recent activity</p>
        </div>
      )}
    </div>
  );
}

