import { nanoid } from "nanoid";

let hash: (password: string) => Promise<string>;
let compare: (password: string, hash: string) => Promise<boolean>;

// @ts-ignore - Deno global
if (typeof Deno !== "undefined") {
  const bcrypt = await import("https://deno.land/x/bcrypt@v0.4.1/mod.ts");
  hash = bcrypt.hash;
  compare = bcrypt.compare;
} else {
  // @ts-ignore
  const bcrypt = await import("@node-rs/bcrypt");
  hash = bcrypt.hash;
  compare = bcrypt.compare;
}

interface User {
  id: string;
  email: string;
  name: string;
  role: "user" | "admin";
  passwordHash: string;
  createdAt: Date;
}

type PublicUser = Omit<User, "passwordHash">;

function toPublicUser({ passwordHash: _passwordHash, ...user }: User): PublicUser {
  return user;
}

// In-memory storage (replace with database)
const users = new Map<string, User>();

// Demo user
const demoUser: User = {
  id: "demo-user",
  email: "demo@example.com",
  name: "Demo User",
  role: "user",
  passwordHash: await hash("password"),
  createdAt: new Date(),
};
users.set(demoUser.id, demoUser);

export async function createUser(data: {
  email: string;
  name: string;
  password: string;
  role?: "user" | "admin";
}): Promise<PublicUser> {
  const user: User = {
    id: nanoid(),
    email: data.email,
    name: data.name,
    role: data.role ?? "user",
    passwordHash: await hash(data.password),
    createdAt: new Date(),
  };

  users.set(user.id, user);
  return toPublicUser(user);
}

export async function validatePassword(email: string, password: string): Promise<PublicUser | null> {
  const user = Array.from(users.values()).find((u) => u.email === email);
  if (!user) return null;

  const valid = await compare(password, user.passwordHash);
  if (!valid) return null;

  return toPublicUser(user);
}

export async function getUsers(): Promise<PublicUser[]> {
  return Array.from(users.values()).map(toPublicUser);
}

export async function getUser(id: string): Promise<PublicUser | null> {
  const user = users.get(id);
  return user ? toPublicUser(user) : null;
}

