      title,
      description,
      labels,
      assigneeIds,
      milestoneId,
      dueDate,
    });

    return {
      success: true,
      message: `Issue created successfully: #${issue.iid}`,
      issue: {
        id: issue.id,
        iid: issue.iid,
        projectId: issue.project_id,
        title: issue.title,
        state: issue.state,
        labels: issue.labels,
        assignees: issue.assignees.map(({ username, name }) => ({ username, name })),
        webUrl: issue.web_url,
        createdAt: issue.created_at,
      },
    };
  },
});

