import { getAccessToken } from "./token-store.ts";

const QUICKBOOKS_BASE_URL = "https://quickbooks.api.intuit.com/v3";

function getRealmId(): string {
  const realmId = process.env.QUICKBOOKS_REALM_ID;
  if (!realmId) {
    throw new Error("QUICKBOOKS_REALM_ID environment variable is required");
  }
  return realmId;
}

interface QuickBooksResponse<T> {
  QueryResponse?: {
    [key: string]: T[] | number | undefined;
    maxResults?: number;
    startPosition?: number;
  };
  Invoice?: T;
  Customer?: T;
  time?: string;
}

interface QuickBooksInvoice {
  Id: string;
  DocNumber: string;
  TxnDate: string;
  DueDate?: string;
  TotalAmt: number;
  Balance: number;
  CustomerRef: {
    value: string;
    name: string;
  };
  Line: Array<{
    Id: string;
    LineNum: number;
    Description?: string;
    Amount: number;
    DetailType: string;
    SalesItemLineDetail?: {
      ItemRef: {
        value: string;
        name: string;
      };
      Qty?: number;
      UnitPrice?: number;
    };
  }>;
  EmailStatus?: string;
  BillEmail?: {
    Address: string;
  };
  TxnStatus?: string;
  MetaData?: {
    CreateTime: string;
    LastUpdatedTime: string;
  };
}

interface QuickBooksCustomer {
  Id: string;
  DisplayName: string;
  CompanyName?: string;
  GivenName?: string;
  FamilyName?: string;
  PrimaryEmailAddr?: {
    Address: string;
  };
  PrimaryPhone?: {
    FreeFormNumber: string;
  };
  BillAddr?: {
    Line1?: string;
    City?: string;
    CountrySubDivisionCode?: string;
    PostalCode?: string;
  };
  Balance: number;
  Active: boolean;
  MetaData?: {
    CreateTime: string;
    LastUpdatedTime: string;
  };
}

async function quickbooksFetch<T>(
  endpoint: string,
  options: RequestInit = {},
): Promise<T> {
  const token = await getAccessToken();
  if (!token) {
    throw new Error("Not authenticated with QuickBooks. Please connect your account.");
  }

  const url = `${QUICKBOOKS_BASE_URL}/company/${getRealmId()}${endpoint}`;

  const response = await fetch(url, {
    ...options,
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "application/json",
      "Content-Type": "application/json",
      ...options.headers,
    },
  });

  if (!response.ok) {
    const error = await response.json().catch(() => ({}));
    const message = error.Fault?.Error?.[0]?.Message ?? response.statusText;
    throw new Error(`QuickBooks API error: ${response.status} ${message}`);
  }

  return response.json();
}

export async function listInvoices(options?: {
  customerId?: string;
  maxResults?: number;
}): Promise<QuickBooksInvoice[]> {
  const maxResults = options?.maxResults ?? 100;

  const query = options?.customerId
    ? `SELECT * FROM Invoice WHERE CustomerRef = '${options.customerId}' MAXRESULTS ${maxResults}`
    : `SELECT * FROM Invoice MAXRESULTS ${maxResults}`;

  const response = await quickbooksFetch<QuickBooksResponse<QuickBooksInvoice>>(
    `/query?query=${encodeURIComponent(query)}`,
  );

  return response.QueryResponse?.Invoice ?? [];
}

export async function getInvoice(invoiceId: string): Promise<QuickBooksInvoice> {
  const response = await quickbooksFetch<QuickBooksResponse<QuickBooksInvoice>>(
    `/invoice/${invoiceId}`,
  );

  const invoice = response.Invoice;
  if (!invoice) {
    throw new Error(`Invoice ${invoiceId} not found`);
  }

  return invoice;
}

export async function createInvoice(options: {
  customerId: string;
  lineItems: Array<{
    description?: string;
    amount: number;
    itemId?: string;
    quantity?: number;
    unitPrice?: number;
  }>;
  txnDate?: string;
  dueDate?: string;
  customerMemo?: string;
}): Promise<QuickBooksInvoice> {
  const lines = options.lineItems.map((item, index) => {
    const line: Record<string, unknown> = {
      LineNum: index + 1,
      Amount: item.amount,
      DetailType: "SalesItemLineDetail",
    };

    if (item.description) {
      line.Description = item.description;
    }

    if (item.itemId) {
      line.SalesItemLineDetail = {
        ItemRef: { value: item.itemId },
        Qty: item.quantity ?? 1,
        UnitPrice: item.unitPrice ?? item.amount,
      };
    }

    return line;
  });

  const invoiceData: Record<string, unknown> = {
    CustomerRef: { value: options.customerId },
    Line: lines,
    ...(options.txnDate ? { TxnDate: options.txnDate } : {}),
    ...(options.dueDate ? { DueDate: options.dueDate } : {}),
    ...(options.customerMemo
      ? { CustomerMemo: { value: options.customerMemo } }
      : {}),
  };

  const response = await quickbooksFetch<QuickBooksResponse<QuickBooksInvoice>>(
    "/invoice",
    {
      method: "POST",
      body: JSON.stringify(invoiceData),
    },
  );

  const invoice = response.Invoice;
  if (!invoice) {
    throw new Error("Failed to create invoice");
  }

  return invoice;
}

export async function listCustomers(options?: {
  maxResults?: number;
  active?: boolean;
}): Promise<QuickBooksCustomer[]> {
  const maxResults = options?.maxResults ?? 100;

  const query =
    options?.active === undefined
      ? `SELECT * FROM Customer MAXRESULTS ${maxResults}`
      : `SELECT * FROM Customer WHERE Active = ${options.active} MAXRESULTS ${maxResults}`;

  const response = await quickbooksFetch<QuickBooksResponse<QuickBooksCustomer>>(
    `/query?query=${encodeURIComponent(query)}`,
  );

  return response.QueryResponse?.Customer ?? [];
}

export async function getCustomer(customerId: string): Promise<QuickBooksCustomer> {
  const response = await quickbooksFetch<QuickBooksResponse<QuickBooksCustomer>>(
    `/customer/${customerId}`,
  );

  const customer = response.Customer;
  if (!customer) {
    throw new Error(`Customer ${customerId} not found`);
  }

  return customer;
}

