function getEnv(key: string): string | undefined {
  // @ts-ignore - Deno global
  if (typeof Deno !== "undefined") return Deno.env.get(key);
  // @ts-ignore - process global
  if (typeof process !== "undefined" && process.env) return process.env[key];
  return undefined;
}

