    const properties: Record<string, string> = {
      email,
      ...(firstname ? { firstname } : {}),
      ...(lastname ? { lastname } : {}),
      ...(phone ? { phone } : {}),
      ...(company ? { company } : {}),
      ...(jobtitle ? { jobtitle } : {}),
      ...(website ? { website } : {}),
