import { getAccessToken } from "./token-store.ts";

const HUBSPOT_BASE_URL = "https://api.hubapi.com";

interface HubSpotPagination {
  after?: string;
  next?: {
    after: string;
    link: string;
  };
}

interface HubSpotResponse<T> {
  results: T[];
  paging?: HubSpotPagination;
}

interface HubSpotContact {
  id: string;
  properties: {
    email?: string;
    firstname?: string;
    lastname?: string;
    phone?: string;
    company?: string;
    website?: string;
    jobtitle?: string;
    createdate?: string;
    lastmodifieddate?: string;
    [key: string]: string | undefined;
  };
  createdAt: string;
  updatedAt: string;
  archived: boolean;
}

interface HubSpotCompany {
  id: string;
  properties: {
    name?: string;
    domain?: string;
    city?: string;
    state?: string;
    country?: string;
    industry?: string;
    phone?: string;
    createdate?: string;
    [key: string]: string | undefined;
  };
  createdAt: string;
  updatedAt: string;
  archived: boolean;
}

interface HubSpotDeal {
  id: string;
  properties: {
    dealname?: string;
    amount?: string;
    dealstage?: string;
    pipeline?: string;
    closedate?: string;
    createdate?: string;
    [key: string]: string | undefined;
  };
  createdAt: string;
  updatedAt: string;
  archived: boolean;
}

function buildQueryString(options: {
  limit?: number;
  after?: string;
  properties?: string[];
  defaultProperties: string[];
}): string {
  const params = new URLSearchParams();

  if (options.limit) params.set("limit", options.limit.toString());
  if (options.after) params.set("after", options.after);

  const properties =
    options.properties && options.properties.length > 0
      ? options.properties
      : options.defaultProperties;

  for (const prop of properties) params.append("properties", prop);

  const queryString = params.toString();
  return queryString ? `?${queryString}` : "";
}

async function hubspotFetch<T>(endpoint: string, options: RequestInit = {}): Promise<T> {
  const token = await getAccessToken();
  if (!token) {
    throw new Error("Not authenticated with HubSpot. Please connect your account.");
  }

  const response = await fetch(`${HUBSPOT_BASE_URL}${endpoint}`, {
    ...options,
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
      ...options.headers,
    },
  });

  if (!response.ok) {
    const error = await response.json().catch(() => ({} as { message?: string }));
    throw new Error(
      `HubSpot API error: ${response.status} ${error.message || response.statusText}`,
    );
  }

  return response.json();
}

// ============================================================================
// CONTACTS
// ============================================================================

export function listContacts(options?: {
  limit?: number;
  after?: string;
  properties?: string[];
}): Promise<HubSpotResponse<HubSpotContact>> {
  const query = buildQueryString({
    limit: options?.limit,
    after: options?.after,
    properties: options?.properties,
    defaultProperties: ["email", "firstname", "lastname", "phone", "company", "jobtitle"],
  });

  return hubspotFetch<HubSpotResponse<HubSpotContact>>(`/crm/v3/objects/contacts${query}`);
}

export function getContact(contactId: string, properties?: string[]): Promise<HubSpotContact> {
  const query = buildQueryString({
    properties,
    defaultProperties: ["email", "firstname", "lastname", "phone", "company", "jobtitle", "website"],
  });

  return hubspotFetch<HubSpotContact>(`/crm/v3/objects/contacts/${contactId}${query}`);
}

export function createContact(properties: {
  email: string;
  firstname?: string;
  lastname?: string;
  phone?: string;
  company?: string;
  website?: string;
  jobtitle?: string;
  [key: string]: string | undefined;
}): Promise<HubSpotContact> {
  return hubspotFetch<HubSpotContact>("/crm/v3/objects/contacts", {
    method: "POST",
    body: JSON.stringify({ properties }),
  });
}

export function updateContact(
  contactId: string,
  properties: {
    email?: string;
    firstname?: string;
    lastname?: string;
    phone?: string;
    company?: string;
    website?: string;
    jobtitle?: string;
    [key: string]: string | undefined;
  },
): Promise<HubSpotContact> {
  return hubspotFetch<HubSpotContact>(`/crm/v3/objects/contacts/${contactId}`, {
    method: "PATCH",
    body: JSON.stringify({ properties }),
  });
}

export function searchContacts(options: {
  query?: string;
  filterGroups?: Array<{
    filters: Array<{
      propertyName: string;
      operator: string;
      value: string;
    }>;
  }>;
  properties?: string[];
  limit?: number;
  after?: string;
}): Promise<HubSpotResponse<HubSpotContact>> {
  const body: Record<string, unknown> = {
    properties:
      options.properties && options.properties.length > 0
        ? options.properties
        : ["email", "firstname", "lastname", "phone", "company", "jobtitle"],
  };

  if (options.filterGroups) body.filterGroups = options.filterGroups;
  if (options.limit) body.limit = options.limit;
  if (options.after) body.after = options.after;

  return hubspotFetch<HubSpotResponse<HubSpotContact>>("/crm/v3/objects/contacts/search", {
    method: "POST",
    body: JSON.stringify(body),
  });
}

// ============================================================================
// COMPANIES
// ============================================================================

export function listCompanies(options?: {
  limit?: number;
  after?: string;
  properties?: string[];
}): Promise<HubSpotResponse<HubSpotCompany>> {
  const query = buildQueryString({
    limit: options?.limit,
    after: options?.after,
    properties: options?.properties,
    defaultProperties: ["name", "domain", "city", "state", "industry", "phone"],
  });

  return hubspotFetch<HubSpotResponse<HubSpotCompany>>(`/crm/v3/objects/companies${query}`);
}

export function getCompany(companyId: string, properties?: string[]): Promise<HubSpotCompany> {
  const query = buildQueryString({
    properties,
    defaultProperties: ["name", "domain", "city", "state", "country", "industry", "phone"],
  });

  return hubspotFetch<HubSpotCompany>(`/crm/v3/objects/companies/${companyId}${query}`);
}

export function createCompany(properties: {
  name: string;
  domain?: string;
  city?: string;
  state?: string;
  country?: string;
  industry?: string;
  phone?: string;
  [key: string]: string | undefined;
}): Promise<HubSpotCompany> {
  return hubspotFetch<HubSpotCompany>("/crm/v3/objects/companies", {
    method: "POST",
    body: JSON.stringify({ properties }),
  });
}

// ============================================================================
// DEALS
// ============================================================================

export function listDeals(options?: {
  limit?: number;
  after?: string;
  properties?: string[];
}): Promise<HubSpotResponse<HubSpotDeal>> {
  const query = buildQueryString({
    limit: options?.limit,
    after: options?.after,
    properties: options?.properties,
    defaultProperties: ["dealname", "amount", "dealstage", "pipeline", "closedate"],
  });

  return hubspotFetch<HubSpotResponse<HubSpotDeal>>(`/crm/v3/objects/deals${query}`);
}

export function getDeal(dealId: string, properties?: string[]): Promise<HubSpotDeal> {
  const query = buildQueryString({
    properties,
    defaultProperties: ["dealname", "amount", "dealstage", "pipeline", "closedate"],
  });

  return hubspotFetch<HubSpotDeal>(`/crm/v3/objects/deals/${dealId}${query}`);
}

export function createDeal(properties: {
  dealname: string;
  amount?: string;
  dealstage?: string;
  pipeline?: string;
  closedate?: string;
  [key: string]: string | undefined;
}): Promise<HubSpotDeal> {
  return hubspotFetch<HubSpotDeal>("/crm/v3/objects/deals", {
    method: "POST",
    body: JSON.stringify({ properties }),
  });
}

export function updateDeal(
  dealId: string,
  properties: {
    dealname?: string;
    amount?: string;
    dealstage?: string;
    pipeline?: string;
    closedate?: string;
    [key: string]: string | undefined;
  },
): Promise<HubSpotDeal> {
  return hubspotFetch<HubSpotDeal>(`/crm/v3/objects/deals/${dealId}`, {
    method: "PATCH",
    body: JSON.stringify({ properties }),
  });
}

// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

export function formatContactName(contact: HubSpotContact): string {
  const parts = [contact.properties.firstname, contact.properties.lastname].filter(
    (p): p is string => Boolean(p),
  );

  if (parts.length > 0) return parts.join(" ");
  return contact.properties.email || "Unnamed Contact";
}

export function formatCompanyName(company: HubSpotCompany): string {
  return company.properties.name || company.properties.domain || "Unnamed Company";
}

export function formatDealName(deal: HubSpotDeal): string {
  return deal.properties.dealname || "Unnamed Deal";
}

export type { HubSpotCompany, HubSpotContact, HubSpotDeal, HubSpotResponse };

