import { getAccessToken } from "./token-store.ts";

const FIGMA_BASE_URL = "https://api.figma.com/v1";

export interface FigmaFile {
  document: FigmaNode;
  components: Record<string, FigmaComponent>;
  componentSets: Record<string, FigmaComponentSet>;
