import { getApiKey, getDatabaseUrl } from "./token-store.ts";
import { Client } from "pg";

const NEON_API_BASE_URL = "https://console.neon.tech/api/v2";

interface NeonProject {
  id: string;
  platform_id: string;
  region_id: string;
  name: string;
  provisioner: string;
  default_endpoint_settings?: {
    autoscaling_limit_min_cu: number;
    autoscaling_limit_max_cu: number;
    suspend_timeout_seconds: number;
  };
  settings?: {
    quota?: {
      active_time_seconds?: number;
      compute_time_seconds?: number;
      written_data_bytes?: number;
      data_transfer_bytes?: number;
    };
  };
  pg_version: number;
  store_passwords: boolean;
  creation_source: string;
  created_at: string;
  updated_at: string;
  proxy_host: string;
  branch_logical_size_limit: number;
  branch_logical_size_limit_bytes: number;
  cpu_used_sec: number;
  maintenance_starts_at?: string;
}

interface NeonBranch {
  id: string;
  project_id: string;
  parent_id?: string;
  parent_lsn?: string;
  parent_timestamp?: string;
  name: string;
  current_state: string;
  pending_state?: string;
  logical_size?: number;
  creation_source: string;
  primary?: boolean;
  default?: boolean;
  protected?: boolean;
  cpu_used_sec: number;
  compute_time_sec?: number;
  active_time_sec?: number;
  written_data_bytes?: number;
  data_transfer_bytes?: number;
  created_at: string;
  updated_at: string;
}

interface NeonProjectsResponse {
