  Amount?: number;
  StageName: string;
  Probability?: number;
  CloseDate: string;
  Type?: string;
  LeadSource?: string;
  Description?: string;
  NextStep?: string;
  IsClosed: boolean;
  IsWon: boolean;
  ForecastCategory?: string;
  CreatedDate: string;
  LastModifiedDate: string;
